begin;
alter table public.invoices add column if not exists invoice_number text;alter table public.invoices add column if not exists client_email text;alter table public.invoices add column if not exists client_phone text;alter table public.invoices add column if not exists billing_address text;alter table public.invoices add column if not exists issue_date date default current_date;alter table public.invoices add column if not exists due_date date;alter table public.invoices add column if not exists currency text not null default 'USD';alter table public.invoices add column if not exists subtotal numeric not null default 0;alter table public.invoices add column if not exists tax_amount numeric not null default 0;alter table public.invoices add column if not exists discount_amount numeric not null default 0;alter table public.invoices add column if not exists total numeric not null default 0;alter table public.invoices add column if not exists notes text;alter table public.invoices add column if not exists terms text;alter table public.invoices add column if not exists source text not null default 'manual';alter table public.invoices add column if not exists source_execution_id uuid references public.agent_executions(id) on delete set null;alter table public.invoices add column if not exists sent_at timestamptz;alter table public.invoices add column if not exists paid_at timestamptz;alter table public.invoices add column if not exists updated_at timestamptz not null default now();
create table if not exists public.invoice_line_items(id uuid primary key default gen_random_uuid(),invoice_id uuid not null references public.invoices(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,description text not null,quantity numeric not null default 1 check(quantity>0),unit_price numeric not null default 0 check(unit_price>=0),line_total numeric not null default 0 check(line_total>=0),position integer not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create unique index if not exists invoices_user_number_idx on public.invoices(user_id,invoice_number) where invoice_number is not null;create unique index if not exists invoices_alma_execution_idx on public.invoices(user_id,source_execution_id) where source='alma_chat' and source_execution_id is not null;create index if not exists invoice_lines_invoice_idx on public.invoice_line_items(invoice_id,user_id);
alter table public.invoice_line_items enable row level security;create policy "Users manage own invoice items" on public.invoice_line_items for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
commit;
